import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a purchase request for a specific chat bubble.
 * Mirrors the server-side PurchaseChatBubbleEvent handler.
 */
export class PurchaseChatBubbleComposer implements IMessageComposer<number[]> {
    private _data: number[];

    constructor(bubbleId: number) {
        this._data = [bubbleId];
        console.log(
            `[📤] PurchaseChatBubbleComposer → attempting to buy bubble ${bubbleId}`
        );
    }

    public getMessageArray(): number[] {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
